{
  "plan": [
    {
      "step": 1,
      "tool": "iam.check_permission",
      "arguments": {
        "resource": "jira.tickets",
        "action": "read",
        "principal": "current_user"
      },
      "depends_on": []
    },
    {
      "step": 2,
      "tool": "iam.check_permission",
      "arguments": {
        "resource": "calendar.events",
        "action": "read_write",
        "principal": "current_user"
      },
      "depends_on": []
    },
    {
      "step": 3,
      "tool": "iam.check_permission",
      "arguments": {
        "resource": "slack.channels",
        "action": "post",
        "principal": "current_user"
      },
      "depends_on": []
    },
    {
      "step": 4,
      "tool": "jira.list_tickets",
      "arguments": {
        "project": "CURRENT_PROJECT",
        "status": ["Open", "In Progress", "To Do"],
        "fields": ["summary", "description", "priority", "assignee", "labels", "acceptance_criteria"],
        "max_results": 50
      },
      "depends_on": [1]
    },
    {
      "step": 5,
      "tool": "calendar.list_events",
      "arguments": {
        "team_members": ["$4.assignees"],
        "time_range": {
          "start": "now",
          "end": "now+5d"
        },
        "include_busy_slots": true,
        "timezone": "UTC"
      },
      "depends_on": [2, 4]
    },
    {
      "step": 6,
      "tool": "audit.log_action",
      "arguments": {
        "action": "READ_JIRA_REQUIREMENTS",
        "resource": "jira.tickets",
        "metadata": {
          "tickets_retrieved": "$4.total",
          "project": "CURRENT_PROJECT",
          "ticket_ids": "$4.ticket_ids"
        },
        "status": "success"
      },
      "depends_on": [4]
    },
    {
      "step": 7,
      "tool": "calendar.create_event",
      "arguments": {
        "title": "Cross-Team Standup: Project Requirements Review",
        "description": "Standup to review project requirements retrieved from Jira. Tickets in scope: $4.ticket_ids",
        "attendees": "$4.assignees",
        "duration_minutes": 30,
        "preferred_slot": "$5.next_common_availability",
        "timezone": "UTC",
        "recurrence": "none",
        "location": "Virtual / Video Conference",
        "agenda_items": [
          "Review open Jira requirements: $4.summaries",
          "Assign ownership and clarify blockers",
          "Define acceptance criteria and priority alignment",
          "Set next action items and deadlines"
        ]
      },
      "depends_on": [2, 5]
    },
    {
